let element = null;
let dotNetRef = null;
let timeoutMs = 300000;
let timerId = null;
let isIdle = false;

const activityEvents = ['mousemove', 'keydown', 'click', 'scroll'];

function handleActivity() {
    resetTimer();
    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync('OnUserActive');
    }
}

function resetTimer() {
    if (timerId !== null) {
        clearTimeout(timerId);
    }
    timerId = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('OnUserIdle');
    }, timeoutMs);
}

export function initialize(el, ref, timeout) {
    element = el;
    dotNetRef = ref;
    timeoutMs = timeout;
    isIdle = false;

    for (const event of activityEvents) {
        document.addEventListener(event, handleActivity, { passive: true });
    }
    resetTimer();
}

export function dispose() {
    if (timerId !== null) {
        clearTimeout(timerId);
        timerId = null;
    }
    for (const event of activityEvents) {
        document.removeEventListener(event, handleActivity);
    }
    element = null;
    dotNetRef = null;
}

